export class MemoryLogger {
    entries = [];
    log(level, message, ...data) {
        this.entries.push({
            level,
            message: String(message ?? ""),
            data,
        });
    }
    debug(message, ...data) {
        this.entries.push({
            level: "debug",
            message: String(message ?? ""),
            data,
        });
    }
    errors() {
        return this.entries.filter((entry) => {
            if (entry.level.toLowerCase() === "error") {
                return true;
            }
            return entry.data.some((value) => value instanceof Error);
        });
    }
}
